    COLOR 255 179 0
  END
  CLASS
	NAME "14 - 15"
    EXPRESSION ([pixel] >= 14 AND [pixel] < 15)
    COLOR 255 102 0
  END
  CLASS
	NAME "15 - 16"
    EXPRESSION ([pixel] >= 15 AND [pixel] < 16)
    COLOR 255 164 128
  END
  CLASS
	NAME "16 - 17"
    EXPRESSION ([pixel] >= 16 AND [pixel] < 17)
    COLOR 255 134 128
  END
  CLASS
	NAME "17 - 18"
    EXPRESSION ([pixel] >= 17 AND [pixel] < 18)
    COLOR 230 101 127
  END
  CLASS
	NAME "18 - 19"
    EXPRESSION ([pixel] >= 18 AND [pixel] <= 19)
    COLOR 214 0 121
  END
END # Layer